create table dirkspzm32.ts_job_cfg (
    sid                    varchar2(2 char) not null enable,
    firma_nr               number(6, 0) not null enable,
    ts_job_name            varchar2(50 char) not null enable,
    ts_job_description     varchar2(255 char),
    status                 varchar2(10 char) default 'new' not null enable,
    last_status_text       varchar2(255 char),
    output_dir             varchar2(255 char),
    enabled                varchar2(1 char) default 'T' not null enable,
    last_start_time        date,
    last_exec_duration_sec number(*, 12),
    created_by_login_id    number(*, 0) not null enable,
    modified_by_login_id   number(*, 0),
    create_time            date not null enable,
    last_modified_time     date
);

alter table dirkspzm32.ts_job_cfg
    add constraint pk_ts_job_cfg
        primary key ( sid,
                      firma_nr,
                      ts_job_name )
            using index enable;


